import{_ as o,C as n,o as l,c as s,E as i,w as r,a,a0 as c}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to the Czech Republic","description":"Immigration pathways and relocation guide for the Czech Republic","frontmatter":{"layout":"doc","title":"Moving to the Czech Republic","description":"Immigration pathways and relocation guide for the Czech Republic"},"headers":[],"relativePath":"europe/czech-republic/moving-there.md","filePath":"europe/czech-republic/moving-there.md","lastUpdated":null}'),d={name:"europe/czech-republic/moving-there.md"};function h(g,e,u,m,p,f){const t=n("Badge");return l(),s("div",null,[i(t,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[a("EU Free Movement",-1)])]),_:1}),i(t,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[a("Employee Card System",-1)])]),_:1}),e[2]||(e[2]=c('<h1 id="moving-to-the-czech-republic" tabindex="-1">Moving to the Czech Republic <a class="header-anchor" href="#moving-to-the-czech-republic" aria-label="Permalink to &quot;Moving to the Czech Republic&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>The Czech Republic grants full <strong>free movement rights</strong> to EU/EEA/Swiss citizens:</p><ul><li><strong>Up to 30 days</strong>: No registration required</li><li><strong>Over 30 days</strong>: Must register with the Foreign Police (Cizinecká policie)</li><li><strong>Over 3 months</strong>: Apply for <strong>pobytové oprávnění</strong> (residence permit) at the Ministry of Interior</li><li><strong>Requirements</strong>: Valid passport or ID, proof of employment, sufficient funds, or health insurance</li><li><strong>Right to work</strong>: Automatic</li><li><strong>After 5 years</strong>: Eligible for permanent residence</li><li><strong>After 5 years permanent residence</strong>: Eligible for citizenship (language test required)</li></ul><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Employee Card</td><td>Employment with Czech employer</td><td>Job offer (no labour market test needed for most jobs), degree</td><td>Up to 2 years, renewable</td></tr><tr><td>EU Blue Card</td><td>Highly qualified workers</td><td>Degree + salary threshold (approx. €45,000+/year)</td><td>2 years, renewable</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof (approx. €5,000+/year)</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family of resident</td><td>Relationship proof, accommodation, income</td><td>1 year, renewable</td></tr><tr><td>Zivno (Freelance Visa)</td><td>Self-employment</td><td>Trade license (Živnostenský list), business plan, client list</td><td>1 year, renewable</td></tr></tbody></table><h3 id="zivno-freelance-visa" tabindex="-1">Zivno (Freelance) Visa <a class="header-anchor" href="#zivno-freelance-visa" aria-label="Permalink to &quot;Zivno (Freelance) Visa&quot;">​</a></h3><p>The <strong>Zivno visa</strong> is a popular option for remote workers and freelancers:</p><ul><li>Requires obtaining a <strong>Živnostenský list</strong> (trade license)</li><li>Must show a client base (at least partial in Czech Republic)</li><li>Business plan demonstrating viability</li><li>Minimum income requirements (varies)</li><li>Valid for 1 year, renewable</li><li>Relatively fast processing compared to other visas</li><li>Taxes: ~15% income tax + social/health insurance</li><li>Accountant highly recommended (Czech tax system is complex)</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>The Czech Republic does <strong>not</strong> have a specific digital nomad visa. Remote work options:</p><ul><li><strong>Zivno (Freelance) visa</strong> is the most popular remote work route</li><li><strong>Employee Card</strong> if employed by a Czech company</li><li><strong>Long-term visa for self-employment</strong> — another option for independent workers</li><li>Remote workers on employee cards must have a Czech employer</li><li>Zivno is flexible for freelancers with international clients</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa/Residence</strong>: Check requirements for your nationality</li><li>[ ] <strong>Health Insurance</strong>: EU citizens: EHIC; others: private insurance (then public after registration)</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (English or Czech)</li><li>[ ] <strong>Medical Records</strong>: Translated into Czech</li><li>[ ] <strong>Banking</strong>: International banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (sreality.cz, bezrealitky.cz)</li><li>[ ] <strong>Language</strong>: Czech is very helpful but English is sufficient in Prague</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] <strong>Register with Foreign Police</strong> within 30 days</li><li>[ ] <strong>Apply for residence permit</strong> (pobytové oprávnění) — EU citizens</li><li>[ ] <strong>Get Czech phone number</strong> — T-Mobile, Vodafone, O2</li><li>[ ] <strong>Register with VZP</strong> (public health insurance)</li><li>[ ] <strong>Open bank account</strong> — Česká spořitelna, ČSOB, Moneta, Air Bank</li><li>[ ] <strong>Get Czech ID card</strong> if staying long-term</li><li>[ ] <strong>Register with sexology clinic</strong> if needing HRT</li><li>[ ] <strong>Connect with Trans*parent</strong> or Prague Pride community</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Prague</th><th>Brno</th><th>Ostrava/Others</th></tr></thead><tbody><tr><td>Rent (1-bedroom)</td><td>15,000-25,000 CZK/month</td><td>10,000-16,000 CZK/month</td><td>8,000-13,000 CZK/month</td></tr><tr><td>Groceries</td><td>4,000-7,000 CZK/month</td><td>3,500-6,000 CZK/month</td><td>3,000-5,500 CZK/month</td></tr><tr><td>Utilities</td><td>3,000-6,000 CZK/month</td><td>2,500-5,000 CZK/month</td><td>2,000-4,500 CZK/month</td></tr><tr><td>Public transport</td><td>365 CZK/month (Prague annual)</td><td>475 CZK/month (Brno annual)</td><td>lower</td></tr><tr><td>Eating out</td><td>150-300 CZK/meal</td><td>120-250 CZK/meal</td><td>100-200 CZK/meal</td></tr></tbody></table><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li><strong>Official language</strong>: Czech</li><li><strong>English</strong>: Widely spoken in Prague, especially among under 40s</li><li><strong>German</strong>: Also somewhat common</li><li><strong>Brno</strong>: Good English spoken (large student population)</li><li><strong>Smaller cities</strong>: English much less common</li><li><strong>Integration</strong>: Czech is essential for life outside Prague</li><li>Free Czech courses available for immigrants in some municipalities</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Continental climate</strong>: Cold winters, warm summers</li><li><strong>Winter</strong>: -10°C to 5°C (December-February)</li><li><strong>Summer</strong>: 15°C to 30°C (June-August)</li><li><strong>Best time to arrive</strong>: Spring (April-May) or early autumn (September)</li></ul><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>Prague is the most trans-friendly</strong> city — large LGBTQ+ scene</li><li><strong>Brno</strong> has a growing queer community, especially among students</li><li>Rural areas and smaller towns are very conservative</li><li>Far-right influence is growing but mostly concentrated outside cities</li><li><strong>Sexuologický ústav</strong> in Prague centralizes trans care — gatekeeping model</li><li>Sterilization requirement for legal gender recognition remains a major issue</li><li><strong>Trans*parent</strong> provides community support and advocacy</li><li>Czech society is generally secular but socially conservative on gender issues</li><li>Growing expat community, especially in Prague and Brno</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.mvcr.cz/" target="_blank" rel="noreferrer">Ministry of Interior - Immigration</a></li><li><a href="https://www.vzp.cz/" target="_blank" rel="noreferrer">VZP - General Health Insurance</a></li><li><a href="https://www.sreality.cz/" target="_blank" rel="noreferrer">Sreality - Housing</a></li><li><a href="https://www.transparentprague.cz/" target="_blank" rel="noreferrer">Trans*parent</a></li><li><a href="https://www.praguepride.cz/" target="_blank" rel="noreferrer">Prague Pride</a></li><li><a href="https://www.platforma-roznopravnost.cz/" target="_blank" rel="noreferrer">Platforma pro rovnoprávnost</a></li><li><a href="https://www.policie.cz/" target="_blank" rel="noreferrer">Foreign Police (Cizinecká policie)</a></li></ul>',29))])}const v=o(d,[["render",h]]);export{y as __pageData,v as default};
